class Solution {
    public int numSub(String s) {
        long res = 0, cnt = 0;
        for (char c : s.toCharArray()) {
            cnt = c == '1' ? cnt + 1 : 0;
            res = (res + cnt) % (10 * 10 * 10 * 10 * 10 + 7);
        }
        return (int) res;
    }
}
